`timescale 1 ns / 1 ns

module Synchronous_Delay_block1
          (  input logic clk,
             input logic reset,
             input logic enb,
             input logic u,
             input logic E,
             output logic y);


  logic [2:0] Delay_reg;  /* ufix1 [3] */
  logic Delay_out1;


  always_ff @(posedge clk)
    begin : Delay_process
      if (reset == 1'b1) begin
        Delay_reg <= '{default :1'b0};
      end
      else begin
        if (enb && E) begin
          Delay_reg[0] <= u;
          Delay_reg[32'sd2:32'sd1] <= Delay_reg[32'sd1:32'sd0];
        end
      end
    end

  assign Delay_out1 = Delay_reg[2];

  assign y = Delay_out1;

endmodule  // Synchronous_Delay_block1

